<?php $db=Database::connection(); $p=$db->query('SELECT COALESCE(SUM(total_amount),0) t FROM purchase_invoices WHERE invoice_date=CURDATE()')->fetch(); $s=$db->query('SELECT COALESCE(SUM(total_amount),0) t FROM sales_invoices WHERE invoice_date=CURDATE()')->fetch(); ?>
<div class='container py-4'><h3>Dashboard</h3><p>Today Purchase: <?=formatIndianCurrency($p['t'])?></p><p>Today Sales: <?=formatIndianCurrency($s['t'])?></p><canvas id='c'></canvas></div><script src='https://cdn.jsdelivr.net/npm/chart.js'></script><script>new Chart(document.getElementById('c'),{type:'bar',data:{labels:['Purchase','Sales'],datasets:[{data:[<?=$p['t']?>,<?=$s['t']?>]}]}});</script>
